"use client";

import { mergeProps, useRender } from "@base-ui/react";
import { Checkbox as CheckboxPrimitive } from "@base-ui/react/checkbox";
import { Input as InputPrimitive } from "@base-ui/react/input";
import { Radio as RadioPrimitive } from "@base-ui/react/radio";
import { RadioGroup as RadioGroupPrimitive } from "@base-ui/react/radio-group";
import * as stylex from "@stylexjs/stylex";
import type * as React from "react";
import type { _BaseDivProps, PropsWithStylex } from "@/utils/stylex.utils";
import { inputGroupStyles } from "./input-group.styles";

type Align = "inline-start" | "inline-end" | "block-start" | "block-end";

type InputGroupProps = PropsWithStylex<React.ComponentProps<"fieldset">>;

function InputGroup({ style, ...props }: InputGroupProps): React.ReactElement {
	const groupStyleProps = stylex.props(inputGroupStyles.group, style);
	return <fieldset {...groupStyleProps} data-slot="input-group" {...props} />;
}

type InputGroupAddonProps = _BaseDivProps & {
	align?: Align;
};

function InputGroupAddon({
	align = "inline-start",
	style,
	...props
}: InputGroupAddonProps): React.ReactElement {
	const addonStyleProps = stylex.props(
		inputGroupStyles.addon,
		align === "inline-start" && inputGroupStyles.addonInlineStart,
		align === "inline-end" && inputGroupStyles.addonInlineEnd,
		align === "block-start" && inputGroupStyles.addonBlockStart,
		align === "block-end" && inputGroupStyles.addonBlockEnd,
		style,
	);

	return (
		// biome-ignore lint/a11y/noStaticElementInteractions: div acts as a focus proxy for the inner input
		<div
			{...addonStyleProps}
			data-align={align}
			data-slot="input-group-addon"
			role="presentation"
			onMouseDown={(e: React.MouseEvent<HTMLDivElement>) => {
				const target = e.target as HTMLElement;
				const isInteractive = target.closest(
					"button, a, input, select, textarea, [role='button'], [role='combobox'], [role='listbox'], [data-slot='select-trigger']",
				);
				if (isInteractive) return;
				e.preventDefault();
				const parent = e.currentTarget.parentElement;
				const input = parent?.querySelector<
					HTMLInputElement | HTMLTextAreaElement
				>("input, textarea");
				if (input && !parent?.querySelector("input:focus, textarea:focus")) {
					input.focus();
				}
			}}
			{...props}
		/>
	);
}

type InputGroupTextProps = React.ComponentProps<"span">;

function InputGroupText({
	className,
	...props
}: InputGroupTextProps): React.ReactElement {
	const textProps = stylex.props(inputGroupStyles.text);
	return (
		<span
			className={[textProps.className, className].filter(Boolean).join(" ")}
			{...props}
		/>
	);
}

type InputGroupInputProps = Omit<
	InputPrimitive.Props & React.RefAttributes<HTMLInputElement>,
	"style"
>;

function InputGroupInput({
	className,
	...props
}: InputGroupInputProps): React.ReactElement {
	const inputProps = stylex.props(inputGroupStyles.input);
	return (
		<InputPrimitive
			{...inputProps}
			className={[inputProps.className, className].filter(Boolean).join(" ")}
			data-slot="input-control"
			{...props}
		/>
	);
}

type InputGroupTextareaProps = Omit<
	React.ComponentPropsWithoutRef<"textarea">,
	"style"
>;

function InputGroupTextarea({
	...props
}: InputGroupTextareaProps): React.ReactElement {
	const textareaProps = stylex.props(inputGroupStyles.textarea);
	return (
		<textarea
			{...textareaProps}
			rows={4}
			data-slot="textarea-control"
			{...props}
		/>
	);
}

function InputGroupMenu({
	className,
	render,
	...props
}: useRender.ComponentProps<"nav">): React.ReactElement {
	const menuProps = stylex.props(inputGroupStyles.menu);
	return useRender({
		defaultTagName: "nav",
		props: mergeProps<"nav">(
			{
				...menuProps,
				className: [menuProps.className, className].filter(Boolean).join(" "),
				"data-slot": "input-group-menu",
			} as never,
			props,
		),
		render,
	});
}

const InputGroupCheckboxItem = CheckboxPrimitive.Root;
const InputGroupRadioGroup = RadioGroupPrimitive;
const InputGroupRadioItem = RadioPrimitive.Root;

export type {
	InputGroupAddonProps,
	InputGroupInputProps,
	InputGroupProps,
	InputGroupTextareaProps,
};
export {
	InputGroup,
	InputGroupAddon,
	InputGroupCheckboxItem,
	InputGroupInput,
	InputGroupMenu,
	InputGroupRadioGroup,
	InputGroupRadioItem,
	InputGroupText,
	InputGroupTextarea,
};

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import { borderRadius, fontSize, spacing } from "@/lib/theme/tokens.stylex";

export const inputGroupStyles = stylex.create({
	group: {
		position: "relative",
		display: "inline-flex",
		width: "100%",
		minWidth: 0,
		alignItems: "center",
		borderRadius: borderRadius.large,
		borderWidth: 1,
		borderStyle: "solid",
		borderColor: theme.border,
		color: theme.contentPrimary,
		fontSize: fontSize.small,
		boxSizing: "border-box",
		minHeight: "40px",
		overflow: "hidden",
		transitionProperty: "border-color, box-shadow",
		transitionDuration: "150ms",
		":focus-within": {
			borderColor: theme.borderStrong,
			boxShadow: `0 0 0 2px ${theme.borderStrong}`,
		},
		":has([aria-invalid='true'])": {
			borderColor: theme.sentimentNegative,
		},
		":has([aria-invalid='true']:focus-visible)": {
			borderColor: theme.sentimentNegative,
			boxShadow: `0 0 0 2px ${theme.sentimentNegative}`,
		},
		":has(:disabled)": {
			opacity: 0.64,
			cursor: "not-allowed",
		},
		":has([data-align='block-start'], [data-align='block-end'])": {
			flexDirection: "column",
		},
	},
	addon: {
		display: "flex",
		alignItems: "center",
		justifyContent: "center",
		cursor: "text",
		flexShrink: 0,
		color: theme.contentSecondary,
		userSelect: "none",
		fontSize: fontSize.small,
		":has(:last-child[data-slot='badge'])": {
			marginInlineStart: 0,
		},
	},
	addonInlineStart: {
		paddingTop: "0px",
		paddingBottom: "0px",
		paddingLeft: "8px",
		paddingRight: "4px",
		alignSelf: "center",
	},
	addonInlineEnd: {
		order: 1,
		paddingLeft: "4px",
		paddingRight: "4px",
		alignSelf: "stretch",
		display: "flex",
		alignItems: "center",
	},
	addonBlockStart: {
		order: -1,
		width: "100%",
		justifyContent: "flex-start",
		paddingTop: "4px",
		paddingLeft: "4px",
		paddingRight: "4px",
	},
	addonBlockEnd: {
		order: 1,
		width: "100%",
		justifyContent: "flex-start",
		paddingBottom: "4px",
		paddingLeft: "4px",
		paddingRight: "4px",
	},
	text: {
		display: "flex",
		alignItems: "center",
		gap: spacing.small,
		whiteSpace: "nowrap",
		lineHeight: 1,
		color: theme.contentSecondary,
	},
	menu: {
		display: "flex",
		flexDirection: "column",
	},
	input: {
		flex: 1,
		minWidth: 0,
		width: "100%",
		height: "100%",
		border: "none",
		outline: "none",
		backgroundColor: "inherit",
		paddingTop: "8px",
		paddingBottom: "6px",
		paddingLeft: "8px",
		paddingRight: "8px",
		borderWidth: 0,
		fontSize: fontSize.small,
		color: theme.contentPrimary,
		"::placeholder": {
			color: theme.contentDisabled,
		},
		boxSizing: "border-box",
		lineHeight: 1.5,
		":disabled": {
			opacity: 0.5,
			cursor: "not-allowed",
		},
	},
	textarea: {
		flex: 1,
		minWidth: 0,
		width: "100%",
		border: "none",
		outline: "none",
		backgroundColor: "transparent",
		paddingTop: "8px",
		paddingBottom: "8px",
		borderWidth: 0,
		paddingLeft: "10px",
		paddingRight: "10px",
		fontSize: fontSize.small,
		color: theme.contentPrimary,
		resize: "none",
		"::placeholder": {
			color: theme.contentDisabled,
		},
	},
});
